// Riceve il database fornitori JSON e lo salva nello static data GLOBALE
// Questo static data è condiviso tra tutti i workflow
const input = $input.first().json;
const suppliersData = input.body || input;

// Salva nello static data globale del workflow 01
// NOTA: ogni workflow ha il proprio static data.
// Per condividerlo, salviamo qui e il workflow 01 leggerà da qui.
const staticData = $getWorkflowStaticData('global');

staticData.suppliers_db = suppliersData;

const totale = suppliersData.metadata?.totale_fornitori || 0;
const categorie = Object.keys(suppliersData.categorie || {}).length;

return {
  json: {
    success: true,
    message: `Database fornitori caricato: ${totale} fornitori in ${categorie} categorie`,
    totale_fornitori: totale,
    categorie: categorie
  }
};
